                        {
                            bb.ToJson();
                            bb.Ignore(x => x.Id);
                            bb.Property(x => x.AlternateId).HasJsonPropertyName("NotKey");
                            bb.WithOwner(e => e.EntityWithOneProperty);
                            bb.OwnsOne(
                                x => x.EntityWithStringKey, bbb =>
                                {
                                    bbb.Ignore(x => x.Id);
                                    bbb.OwnsMany(x => x.Properties, bbbb => bbbb.HasJsonPropertyName("JsonProps"));
                                });
                        });
                });
            },
            AddBoilerPlate(
                GetHeading()
                + """
