                                            b3.Property<int>("Id");

                                            b3.Property<string>("Name");

                                            b3.HasKey("EntityWithStringKeyEntityWithTwoPropertiesEntityWithOnePropertyId", "__synthesizedOrdinal");

                                            b3.ToTable("EntityWithOneProperty", "DefaultSchema");

